mapper.select:
SELECT * FROM ( SELECT TT1.SUP_NO, TT1.SUP_CN, TT1.SUP_ANS_CN, TT1.SUP_REG, TT1.SUP_REG_HM, TT1.SUP_ANS_REG, TT1.SUP_ANS_REG_HM, TT1.REG_NO, TT1.SUP_YN, ROW_NUMBER() OVER (ORDER BY TT1.SUP_NO DESC) AS rnum, COUNT(*) OVER() AS total_count FROM SUPPORT TT1 WHERE 1 = 1
AND (TT1.SUP_CN LIKE '%' || #{searchWord} || '%' OR TT1.SUP_ANS_CN LIKE '%' || #{searchWord} || '%')
) A WHERE A.rnum BETWEEN (#{pageSize} * (#{pageNo} - 1) + 1) AND (#{pageSize} * #{pageNo})
